/**
 * @file
 * @kit ArkUI
 */

/**
 * Defines the two-dimensional vector, which contains the x and y coordinates and indicates the position relationship.
 *
 * @syscap SystemCapability.ArkUI.ArkUI.Full
 * @systemapi
 * @stagemodelonly
 * @since 26.0.0 dynamic
 */
declare type Vector2 = import('../api/arkui/Graphics').Vector2;

/**
 * Defines the four-dimensional vector, which contains x, y, z, and w coordinates that indicate the barrel distortion 
 * degree.
 *
 * @syscap SystemCapability.ArkUI.ArkUI.Full
 * @systemapi
 * @stagemodelonly
 * @since 26.0.0 dynamic
 */
declare type Vector4 = import('../api/arkui/Graphics').Vector4;

/**
 * Defines the spatial distortion parameters.
 * 
 * > **NOTE**
 * >
 * > - The coordinates of the four corners of the component can be set as follows: top-left corner: [0, 0], top-right 
 * > corner: [1, 0], bottom-left corner: [0, 1], bottom-right corner: [1, 1].
 * >
 * > - For example, if the **bottomLeft** attribute is set to **[0.5, 0.5]**, the bottom-left corner is deformed to the 
 * > position of the component center, and the corresponding distortion effect is generated.
 * >
 * > - When setting the coordinates of the four corners, ensure they follow spatial logic. For example, if **topLeft** 
 * > is **[0, 0.7]** and **bottomLeft** is **[0, 0.2]**, the top-left corner is lower than the bottom-left corner, which
 * > violates the spatial logic and may cause rendering exceptions.
 *
 * @syscap SystemCapability.ArkUI.ArkUI.Full
 * @systemapi
 * @stagemodelonly
 * @since 26.0.0 dynamic
 */
declare interface DistortionParam {
  /**
   * Coordinates of the top-left corner.
   * 
   * Default value: **[0, 0]**
   *
   * @default [0, 0]
   * @syscap SystemCapability.ArkUI.ArkUI.Full
   * @systemapi
   * @stagemodelonly
   * @since 26.0.0 dynamic
   */
  topLeft: Vector2;
  /**
   * Coordinates of the top-right corner.
   * 
   * Default value: **[1, 0]**
   *
   * @default [1, 0]
   * @syscap SystemCapability.ArkUI.ArkUI.Full
   * @systemapi
   * @stagemodelonly
   * @since 26.0.0 dynamic
   */
  topRight: Vector2;
  /**
   * Coordinates of the bottom-left corner.
   * 
   * Default value: **[0, 1]**
   *
   * @default [0, 1]
   * @syscap SystemCapability.ArkUI.ArkUI.Full
   * @systemapi
   * @stagemodelonly
   * @since 26.0.0 dynamic
   */
  bottomLeft: Vector2;
  /**
   * Coordinates of the bottom-right corner.
   * 
   * Default value: **[1, 1]**
   *
   * @default [1, 1]
   * @syscap SystemCapability.ArkUI.ArkUI.Full
   * @systemapi
   * @stagemodelonly
   * @since 26.0.0 dynamic
   */
  bottomRight: Vector2;
  /**
   * Barrel distortion degree of the four edges.
   * 
   * The four values in **Vector4** are as follows: **x** indicates the left edge, **y** indicates the right edge, **z**
   * indicates the top edge, and **w** indicates the bottom edge.
   * 
   * Default value: **[0, 0, 0, 0]**
   * 
   * A positive value indicates outward distortion, and a negative value indicates inward distortion. When the absolute 
   * value of the distortion parameter reaches 1, the distortion degree is extreme.
   * 
   * Recommended value range for x, y, z, and w: **[-1, 1]**
   *
   * @default [0, 0, 0, 0]
   * @syscap SystemCapability.ArkUI.ArkUI.Full
   * @systemapi
   * @stagemodelonly
   * @since 26.0.0 dynamic
   */
  barrelDistortion: Vector4;
}

/**
 * Defines the DistortionComponent constructor options.
 *
 * @syscap SystemCapability.ArkUI.ArkUI.Full
 * @systemapi
 * @stagemodelonly
 * @since 26.0.0 dynamic
 */
declare interface DistortionComponentOptions {
  /**
   * Spatial distortion parameters. The spatial distortion effect is generated by specifying the position relationship 
   * of four corners and the barrel distortion degree of four edges.
   *
   * @syscap SystemCapability.ArkUI.ArkUI.Full
   * @systemapi
   * @stagemodelonly
   * @since 26.0.0 dynamic
   */
  distortion?: DistortionParam;
}

/**
 * Create DistortionComponent.
 *
 * @syscap SystemCapability.ArkUI.ArkUI.Full
 * @systemapi
 * @stagemodelonly
 * @since 26.0.0 dynamic
 */
interface DistortionComponentInterface {
  /**
   * Creates a DistortionComponent with content.
   *
   * @param { DistortionComponentOptions } [options] - DistortionComponent Options.
   * @returns { DistortionComponentAttribute }
   * @syscap SystemCapability.ArkUI.ArkUI.Full
   * @systemapi
   * @stagemodelonly
   * @since 26.0.0 dynamic
   */
  (options?: DistortionComponentOptions): DistortionComponentAttribute;
}

/**
 * Defines the DistortionComponent attribute functions
 *
 * @syscap SystemCapability.ArkUI.ArkUI.Full
 * @systemapi
 * @stagemodelonly
 * @since 26.0.0 dynamic
 */
declare class DistortionComponentAttribute extends CommonMethod<DistortionComponentAttribute> {}

/**
 * Defines DistortionComponent.
 *
 * @syscap SystemCapability.ArkUI.ArkUI.Full
 * @systemapi
 * @stagemodelonly
 * @since 26.0.0 dynamic
 */
declare const DistortionComponent: DistortionComponentInterface;
